<template>
  <div class="WelcomeImage" :style="`height: ${appHeight}px`" v-resize="updateHeight">
    <v-img
      src="@/assets/images/WelcomeImage.jpg"
      :height="appHeight"
      :position="position"
      class="welcomeImg pa-3"
      dark
    >
      <v-container fill-height>
        <v-row>
          <v-col class="text-center mb-7" cols="12">
            <h1 class="text px-4 pt-3 noselect" v-if="!landingPage">{{ title }}</h1>
            <h1 class="white--text logo noselect" v-else>{{ title }}</h1>
          </v-col>
        </v-row>
      </v-container>
    </v-img>

    <svg
      class="arrow"
      style="enable-background:new 0 0 512 512;"
      version="1.1"
      viewBox="0 0 512 512"
      xml:space="preserve"
      xmlns="http://www.w3.org/2000/svg"
      xmlns:xlink="http://www.w3.org/1999/xlink"
      v-if="!alt"
      @click="$emit('scroll')"
    >
      <polygon points="396.6,160 416,180.7 256,352 96,180.7 115.3,160 256,310.5 " />
    </svg>
  </div>
</template>

<script>
export default {
  name: "WelcomeImage",
  props: {
    height: {
      type: String,
      default: ""
    },
    position: {
      type: String,
      default: "center center"
    },
    alt: {
      type: Boolean,
      default: false
    },
    landingPage: {
      type: Boolean,
      default: false
    },
    title: String
  },
  data() {
    return {
      space: "&nbsp;",
      appHeight: "100vh"
    };
  },
  methods: {
    updateHeight() {
      // If not mobile make responsive
      if (
        !(
          navigator.maxTouchPoints || "ontouchstart" in document.documentElement
        )
      ) {
        if (this.height === "") this.appHeight = window.innerHeight.toString();
        else this.appHeight = this.height;
      }
    }
  },
  created() {
    // If mobile, calculate only one time
    if (
      navigator.maxTouchPoints ||
      "ontouchstart" in document.documentElement
    ) {
      if (this.height === "") this.appHeight = window.innerHeight.toString();
      else this.appHeight = this.height;
    }
  }
};
</script>

<style scoped>
.welcomeImg {
  border: 13px solid black;
}

.arrow {
  position: relative;
  bottom: 150px;
  left: 50%;
  z-index: 5;
  width: 80px;
  height: 80px;
  margin-left: -40px;
  text-align: center;
  cursor: pointer;
  fill: white;
}

.logo {
  font-family: "Zilla Slab Highlight", cursive;

  font-size: 3rem !important;
  font-weight: 300;
}

svg {
  font-family: "Special Elite", cursive !important;
  font-size: 50px;
  font-weight: bold;
}

.img-layer {
  fill: url(#p-img);
}

.gradient-layer {
  fill: url(#gr-overlay);
}

.text {
  font-family: "Special Elite", cursive !important;
  background-color: white;
  color: black;
  font-weight: bold;
  margin: 0 auto;
  width: fit-content;

  mix-blend-mode: screen;

  font-size: 3.75rem !important;
  font-weight: 300;
  line-height: 3.75rem;
  letter-spacing: -0.0083333333em !important;
}

@media screen and (min-width: 1000px) {
  .text {
    font-size: 4.5rem !important;
    line-height: 4.5rem;
  }

  .logo {
    font-size: 5rem !important;
    font-weight: 300;
  }
}
</style>