<template>
  <div v-scroll="handleScroll">
    <!-- The landing image -->
    <v-row>
      <v-col class="pa-0 mt-n3">
        <WelcomeImage
          title="Simone Carletti"
          @scroll="$vuetify.goTo($refs.navbar, options)"
          landingPage
        />
      </v-col>
    </v-row>

    <!-- Navbar -->
    <v-row>
      <!-- :class="{'lightOpacity': showNavbarAtTop}" style="height: 7vh; transition: none;" -->

      <v-col class="pa-0 pt-1 mb-n1" style="height: 7vh">
        <v-app-bar
          flat
          :color=" showNavbarAtTop ? '' : 'transparent'"
          :style="{ opacity: navbarOpacity, height: '7vh', transition: 'none' }"
          :fixed="showNavbarAtTop"
          scroll
          ref="navbar"
        >
          <v-toolbar-title class="typewriter noselect">Simone Carletti</v-toolbar-title>

          <v-spacer></v-spacer>

          <v-btn text @click="overlay = !overlay" :ripple="false">
            <v-toolbar-title class="typewriter">Menu</v-toolbar-title>
          </v-btn>
        </v-app-bar>
      </v-col>
    </v-row>

    <!-- The images tiles -->
    <div style="min-height: 100vh;" class="tiles">
      <masonry :cols="{default: 3, 1100: 2, 400: 1}" :gutter="{default: '20px', 700: '15px'}">
        <v-img :src="img.src" class="py-2" v-for="(img, i) in images" :key="i" contain>
          <template v-slot:placeholder>
            <v-row class="fill-height ma-0" align="center" justify="center">
              <v-progress-circular indeterminate color="grey lighten-5"></v-progress-circular>
            </v-row>
          </template>
        </v-img>
      </masonry>
    </div>

    <!-- Bottom right instagram icon -->
    <v-btn
      icon
      txt
      color="black"
      x-large
      :ripple="false"
      fixed
      bottom
      right
      @click="goTo('https://www.instagram.com/iostreet/')"
    >
      <v-icon>mdi-instagram</v-icon>
    </v-btn>

    <!-- Menu Overlay -->
    <v-overlay :value="overlay" color="white" opacity="0.91">
      <v-container>
        <v-row class="text-right">
          <v-col>
            <v-btn text icon fixed top right x-large color="black" @click="overlay = !overlay">
              <v-icon light>mdi-close</v-icon>
            </v-btn>
          </v-col>
        </v-row>
        <v-row class="text-center">
          <v-col>
            <router-link to="/about" class="black--text link">ABOUT</router-link>
          </v-col>
        </v-row>
        <v-row>
          <v-col>
            <router-link to="/contacts" class="black--text link">CONTACTS</router-link>
          </v-col>
        </v-row>
        <v-row class="mt-12">
          <v-col>
            <v-btn text icon x-large color="black" class="ma-auto">
              <v-icon light>mdi-instagram</v-icon>
            </v-btn>
          </v-col>
        </v-row>
      </v-container>
    </v-overlay>
  </div>
</template>

<script>
// @ is an alias to /src
import WelcomeImage from "@/components/WelcomeImage.vue";

export default {
  name: "home",
  components: {
    WelcomeImage
  },
  data() {
    return {
      images: [],
      overlay: false,
      showNavbarAtTop: false,
      lastScrollPosition: 0,
      navbarOpacity: 0
    };
  },
  created() {
    this.importAll(
      require.context("@/assets/images/", true, /[^WelcomeImage]\.jpg$/)
    );
  },
  methods: {
    goTo(url) {
      window.open(url);
    },
    importAll(r) {
      r.keys().forEach(key =>
        this.images.push({
          src: r(key)
        })
      );
    },
    handleScroll() {
      // Get the current scroll position
      const currentScrollPosition =
        window.pageYOffset || document.documentElement.scrollTop;
      // Because of momentum scrolling on mobiles, we shouldn't continue if it is less than zero
      if (currentScrollPosition < 0) {
        return;
      }
      // Here we determine whether we need to show or hide the navbar
      this.showNavbarAtTop = currentScrollPosition >= window.innerHeight;

      /* 
        Formula to calculate the relative opacity
        It calculate the opacity for the navbar, relative to its vicinity to the top.
        It's calculated relative to to 30% of the innerHeight, so when you scrolled 70% down is still opacity: 0
        Then it starts to show (increase opacity) until it reaches opacity: 0.95
      */
      if (
        navigator.maxTouchPoints ||
        "ontouchstart" in document.documentElement
      ) {
        this.navbarOpacity = 0.95;
      } else {
        let relativeOpacity =
          -1 *
          ((window.innerHeight - currentScrollPosition) /
            (0.3 * window.innerHeight) -
            1);

        if (relativeOpacity < 0.95) {
          this.navbarOpacity = relativeOpacity;
        }
      }
    }
  },
  computed: {
    options() {
      return {
        duration: 300,
        offset: 0,
        easing: "easeInOutCubic"
      };
    }
  }
};
</script>


